#include <stdio.h>
#include <stdlib.h>
#define MOD 998244353

long long powmod(long long a, long long b) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % MOD;
        a = (a * a) % MOD;
        b >>= 1;
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q, Z;
        scanf("%d %d %d %d", &N, &M, &Q, &Z);
        long long dp[N * M + 1];
        dp[0] = 1;
        for (int i = 1; i <= Q; i++) {
            long long ndp[N * M + 1];
            for (int j = 0; j <= N * M; j++) ndp[j] = 0;
            for (int j = 0; j <= N * M; j++) {
                if (dp[j] == 0) continue;
                for (int k = 0; k <= N * M; k++) {
                    if (j + k > N * M) break;
                    ndp[j + k] = (ndp[j + k] + dp[j] * powmod(N * M - j - k + 1, MOD - 2)) % MOD;
                }
            }
            for (int j = 0; j <= N * M; j++) dp[j] = ndp[j];
        }
        printf("%lld\n", dp[Z]);
    }
    return 0;
}

